s = {1, 2, 3}

# 1. Insertion - O(1) average
s.add(4)
print(s)               # {1, 2, 3, 4}

# 2. Deletion - O(1) average
s.remove(3)            # Raises KeyError if 3 is missing
s.discard(10)          # O(1) - Safe deletion, no error if missing

# 3. Membership Check - O(1) average
print(2 in s)          # True (incredibly fast due to hashing)

# 4. Mathematical Set Operations
a = {1, 2, 3}
b = {3, 4, 5}
print(a | b)           # O(len(a) + len(b)) - Union: {1, 2, 3, 4, 5}
print(a & b)           # O(min(len(a), len(b))) - Intersection: {3}
print(a - b)           # O(len(a)) - Difference: {1, 2}
print(a ^ b)           # O(len(a)) - Symmetric Difference: {1, 2, 4, 5}
